import pandas as pd
import numpy as np

def task_func(data, cols):
    df = pd.DataFrame(data)

    # Ensure that only numeric columns are considered for correlation analysis
    df_numeric = df[cols].select_dtypes(include=['int64', 'float64'])

    if not df_numeric.empty:
        correlation_matrix = df_numeric.corr()
        return tuple((correlation_matrix,))

    else:
        print("No numeric columns found in the provided data.")
        return None
